#!/usr/bin/env node
/**
 * push-signal-to-xlayer.js — Push Sasha's AI signal to X Layer oracle
 *
 * Reads the latest signal from content/mantle-signal.json (generated by
 * mantle-signal.js) and calls SashaOracle.setFee() on X Layer.
 *
 * This is the autonomous bridge between Sasha's off-chain signal pipeline
 * and the on-chain SashaDynamicFeeHook. It runs every 6 hours from the VPS
 * cron (HEARTBEAT.md) — no human intervention needed.
 *
 * Signal → Fee mapping:
 *   "risk-off"  → 10000  (1.0% — protect LPs during uncertainty)
 *   "neutral"   → 3000   (0.3% — standard)
 *   "risk-on"   → 500    (0.05% — attract volume when confident)
 *
 * Pattern: same as erc8004-write.js — provider + wallet + contract call.
 * Non-blocking. Exits 0 always. Errors are logged, never thrown.
 *
 * Usage:
 *   node scripts/push-signal-to-xlayer.js               # live push
 *   node scripts/push-signal-to-xlayer.js --dry-run     # simulate, no tx
 *   node scripts/push-signal-to-xlayer.js --force       # push even if signal unchanged
 *
 * Requires (in .env):
 *   XLAYER_RPC_URL         — X Layer RPC endpoint
 *   XLAYER_AGENT_PK        — Sasha's agent EOA private key for X Layer
 *   XLAYER_ORACLE_ADDRESS  — Deployed SashaOracle contract address
 *
 * Sasha Coin — OKX Build X Hackathon 2026
 */

import { ethers } from 'ethers'
import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const WORKSPACE = process.env.OPENCLAW_WORKSPACE || path.resolve(__dirname, '..')

// ─── CLI args ────────────────────────────────────────────────────────────────

const args     = process.argv.slice(2)
const DRY_RUN  = args.includes('--dry-run')
const FORCE    = args.includes('--force')
// --risk <risk-off|neutral|risk-on> overrides the signal-derived risk level.
// Use for mechanism-demonstration pushes (prove the hook sets all three fee tiers on-chain).
const RISK_ARG = (() => { const i = args.indexOf('--risk'); return i !== -1 ? args[i + 1] : null })()

// ─── Chain config ─────────────────────────────────────────────────────────────

const XLAYER = {
    rpc:      process.env.XLAYER_RPC_URL || 'https://rpc.xlayer.tech',
    chainId:  parseInt(process.env.XLAYER_CHAIN_ID || '196'),
    name:     'X Layer',
    explorer: 'https://www.oklink.com/x-layer',
}

// ─── Signal → Fee mapping ─────────────────────────────────────────────────────

const RISK_TO_FEE = {
    'risk-off': 10000,  // 1.0%  — LPs protected during uncertainty
    'neutral':  3000,   // 0.3%  — standard conditions
    'risk-on':  500,    // 0.05% — attract volume when confident
}

// ─── ABI (minimal) ───────────────────────────────────────────────────────────

const ORACLE_ABI = [
    'function setFee(uint24 fee, string calldata riskLevel) external',
    'function currentFee() external view returns (uint24)',
    'function riskLevel() external view returns (string)',
    'function updatedAt() external view returns (uint256)',
    'function isStale() external view returns (bool)',
    'function updateCount() external view returns (uint256)',
    'function getFeeOrDefault() external view returns (uint24)',
    'function agent() external view returns (address)',
    'event FeeUpdated(uint24 indexed oldFee, uint24 indexed newFee, string riskLevel, uint256 timestamp, uint256 updateCount)',
]

// ─── Helpers ──────────────────────────────────────────────────────────────────

function log(msg)  { console.log(`[xlayer-oracle] ${msg}`) }
function warn(msg) { console.warn(`[xlayer-oracle] ⚠  ${msg}`) }

function loadSignal() {
    const signalPath = path.join(WORKSPACE, 'content', 'mantle-signal.json')
    if (!fs.existsSync(signalPath)) {
        warn('content/mantle-signal.json not found — run mantle-signal.js first')
        return null
    }
    try {
        return JSON.parse(fs.readFileSync(signalPath, 'utf8'))
    } catch (e) {
        warn(`Failed to parse mantle-signal.json: ${e.message}`)
        return null
    }
}

function extractRiskLevel(signal) {
    // Primary: socialBias.riskAppetite
    const social = signal?.socialBias?.riskAppetite
    if (social && RISK_TO_FEE[social] !== undefined) return social

    // Fallback: recommendation.action → infer risk
    const action = signal?.recommendation?.action
    if (action === 'MOVE_TO_STABLE') return 'risk-off'
    if (action === 'OPEN_LP_POSITION' || action === 'SWAP_TO_SOL') return 'risk-on'

    return 'neutral'
}

function logPushState(txHash, fee, riskLevel) {
    const statePath = path.join(WORKSPACE, 'state', 'xlayer-oracle-pushes.json')
    let history = []
    try { history = JSON.parse(fs.readFileSync(statePath, 'utf8')) } catch {}
    history.push({ txHash, fee, riskLevel, pushedAt: new Date().toISOString() })
    // Keep last 100 pushes
    if (history.length > 100) history = history.slice(-100)
    try {
        fs.mkdirSync(path.join(WORKSPACE, 'state'), { recursive: true })
        fs.writeFileSync(statePath, JSON.stringify(history, null, 2))
    } catch (e) { warn(`Could not save push state: ${e.message}`) }
}

// ─── Main ─────────────────────────────────────────────────────────────────────

async function main() {
    log('Starting signal push to X Layer oracle...')

    // 1. Load signal
    const signal = loadSignal()
    if (!signal) { process.exit(0) }

    // --risk override (mechanism demo) wins over the signal-derived level
    const riskLevel = (RISK_ARG && RISK_TO_FEE[RISK_ARG] !== undefined) ? RISK_ARG : extractRiskLevel(signal)
    if (RISK_ARG && RISK_TO_FEE[RISK_ARG] === undefined) { warn(`--risk "${RISK_ARG}" invalid (use risk-off|neutral|risk-on)`); process.exit(0) }
    if (RISK_ARG) log(`risk OVERRIDE via --risk: ${riskLevel}`)
    const fee       = RISK_TO_FEE[riskLevel]
    const signalAge = signal.generatedAt
        ? Math.round((Date.now() - new Date(signal.generatedAt).getTime()) / 60000)
        : 'unknown'

    log(`Signal age: ${signalAge} minutes`)
    log(`Risk level: ${riskLevel}`)
    log(`Fee to push: ${fee} (${(fee / 10000).toFixed(4)}%)`)

    // 2. Check oracle address
    const oracleAddress = process.env.XLAYER_ORACLE_ADDRESS
    if (!oracleAddress) {
        warn('XLAYER_ORACLE_ADDRESS not set — deploy the oracle first (deploy-xlayer-hook.js)')
        process.exit(0)
    }

    // 3. Dry-run
    if (DRY_RUN) {
        log('--- DRY RUN ---')
        log(`Would call: SashaOracle(${oracleAddress}).setFee(${fee}, "${riskLevel}")`)
        log(`On chain:   X Layer (chainId ${XLAYER.chainId})`)
        log('No transaction sent.')
        process.exit(0)
    }

    // 4. Connect
    const pk = process.env.XLAYER_AGENT_PK
    if (!pk) {
        warn('XLAYER_AGENT_PK not set — skipping oracle push (non-blocking)')
        process.exit(0)
    }

    const provider = new ethers.JsonRpcProvider(XLAYER.rpc, {
        chainId: XLAYER.chainId,
        name:    XLAYER.name,
    })
    const wallet = new ethers.Wallet(pk, provider)
    const oracle = new ethers.Contract(oracleAddress, ORACLE_ABI, wallet)

    // 5. Check current oracle state
    let currentFee, currentRisk, stale
    try {
        currentFee  = await oracle.currentFee()
        currentRisk = await oracle.riskLevel()
        stale       = await oracle.isStale()
        log(`Oracle current: fee=${currentFee} risk="${currentRisk}" stale=${stale}`)
    } catch (e) {
        warn(`Could not read oracle state: ${e.message}`)
    }

    // 6. Skip if unchanged (unless --force)
    if (!FORCE && currentFee !== undefined && Number(currentFee) === fee && currentRisk === riskLevel) {
        log(`Oracle already at ${fee} bips (${riskLevel}) — no update needed. Use --force to override.`)
        process.exit(0)
    }

    // 7. Check OKB balance
    const balance    = await provider.getBalance(wallet.address)
    const balanceOKB = parseFloat(ethers.formatEther(balance))
    log(`Agent wallet: ${wallet.address}`)
    log(`OKB balance:  ${balanceOKB}`)
    if (balanceOKB < 0.001) {
        warn(`Low OKB balance (${balanceOKB}) — transaction may fail. Fund at: https://www.okx.com/xlayer/bridge`)
        process.exit(0)
    }

    // 8. Push fee to oracle
    log(`Pushing fee update: ${fee} bips, risk="${riskLevel}"...`)
    try {
        const tx = await oracle.setFee(fee, riskLevel, { gasLimit: 100000n })
        log(`TX submitted: ${tx.hash}`)
        log(`Explorer: ${XLAYER.explorer}/tx/${tx.hash}`)

        // Non-blocking — don't wait for confirmation on VPS cron
        logPushState(tx.hash, fee, riskLevel)

        // Emit structured output for logging
        process.stdout.write(JSON.stringify({
            txHash:    tx.hash,
            fee,
            riskLevel,
            pushedAt:  new Date().toISOString(),
            explorer:  `${XLAYER.explorer}/tx/${tx.hash}`,
        }) + '\n')

    } catch (e) {
        warn(`Oracle push failed: ${e.message}`)
        warn('Sasha will continue operating — fee reverts to DEFAULT (3000) if oracle goes stale.')
    }

    process.exit(0) // always exit 0 — non-blocking
}

main().catch(err => {
    console.warn(`[xlayer-oracle] Fatal: ${err.message}`)
    process.exit(0) // still exit 0 — non-blocking
})
